+
+#include <algorithm>
+#include <cstdint>
+#include <cstdio>
+#include <cstdlib>
+#include <vector>
+
+namespace {
+
+constexpr std::uint64_t kBufferBytes = 4ull * 1024ull * 1024ull * 1024ull;
+constexpr int kThreads = 256;
+constexpr int kBlocks = 2048;
+constexpr int kWarmup = 3;
+constexpr int kSamples = 15;
+
+__global__ __launch_bounds__(kThreads)
+void read_stream(const float4* __restrict__ input,
+                 std::uint64_t vector_count,
+                 volatile float* __restrict__ sink) {
+  const std::uint64_t tid = static_cast<std::uint64_t>(blockIdx.x) * blockDim.x
+                          + threadIdx.x;
+  const std::uint64_t stride = static_cast<std::uint64_t>(gridDim.x) * blockDim.x;
+
+  float sx = 0.0f;
+  float sy = 0.0f;
+  float sz = 0.0f;
+  float sw = 0.0f;
+
+  // The loop is deliberately a grid-stride traversal: every vector is fetched
+  // once, while the large number of resident waves keeps HBM requests in flight.
+  for (std::uint64_t i = tid; i < vector_count; i += stride) {
+    const float4 v = input[i];
+    sx += v.x;
+    sy += v.y;
+    sz += v.z;
+    sw += v.w;
+  }
+
+  __shared__ float partial[kThreads];
+  partial[threadIdx.x] = sx + sy + sz + sw;
+  __syncthreads();
+
+  for (int width = kThreads / 2; width > 0; width >>= 1) {
+    if (threadIdx.x < width) {
+      partial[threadIdx.x] += partial[threadIdx.x + width];
+    }
+    __syncthreads();
+  }
+
+  // Volatile makes the reduction an observable side effect.  One result per
+  // block makes the write traffic negligible relative to the read traffic.
+  if (threadIdx.x == 0) {
+    sink[blockIdx.x] = partial[0];
+  }
+}
+
+[[noreturn]] void fail(const char* what, hipError_t error) {
+  std::fprintf(stderr, "%s: %s\n", what, hipGetErrorString(error));
+  std::exit(EXIT_FAILURE);
+}
+
+void check(hipError_t error, const char* what) {
+  if (error != hipSuccess) {
+    fail(what, error);
+  }
+}
+
+}  // namespace
+
+int main() {
+  check(hipSetDevice(0), "hipSetDevice");
+
+  const std::uint64_t vector_count = kBufferBytes / sizeof(float4);
+  float4* input = nullptr;
+  float* sink = nullptr;
+  check(hipMalloc(reinterpret_cast<void**>(&input), kBufferBytes), "hipMalloc input");
+  check(hipMalloc(reinterpret_cast<void**>(&sink), kBlocks * sizeof(float)),
+        "hipMalloc sink");
+  check(hipMemset(sink, 0, kBlocks * sizeof(float)), "hipMemset sink");
+
+  hipEvent_t start = nullptr;
+  hipEvent_t stop = nullptr;
+  check(hipEventCreate(&start), "hipEventCreate start");
+  check(hipEventCreate(&stop), "hipEventCreate stop");
+
+  dim3 grid(kBlocks);
+  dim3 block(kThreads);
+
+  for (int i = 0; i < kWarmup; ++i) {
+    hipLaunchKernelGGL(read_stream, grid, block, 0, 0, input, vector_count, sink);
+    check(hipGetLastError(), "warmup launch");
+  }
+  check(hipDeviceSynchronize(), "warmup synchronize");
+
+  std::vector<float> milliseconds;
+  milliseconds.reserve(kSamples);
+  for (int i = 0; i < kSamples; ++i) {
+    check(hipEventRecord(start, nullptr), "hipEventRecord start");
+    hipLaunchKernelGGL(read_stream, grid, block, 0, 0, input, vector_count, sink);
+    check(hipGetLastError(), "timed launch");
+    check(hipEventRecord(stop, nullptr), "hipEventRecord stop");
+    check(hipEventSynchronize(stop), "hipEventSynchronize");
+
+    float elapsed = 0.0f;
+    check(hipEventElapsedTime(&elapsed, start, stop), "hipEventElapsedTime");
+    milliseconds.push_back(elapsed);
+  }
+
+  std::sort(milliseconds.begin(), milliseconds.end());
+  const float median_ms = milliseconds[milliseconds.size() / 2];
+  const double bandwidth_gbps =
+      static_cast<double>(kBufferBytes) / (static_cast<double>(median_ms) * 1.0e6);
+
+  // Keep the sink live through the host side as well.  It is not part of the
+  // bandwidth calculation, but prevents whole-program result elision.
+  float sink_value = 0.0f;
+  check(hipMemcpy(&sink_value, sink, sizeof(float), hipMemcpyDeviceToHost),
+        "hipMemcpy sink");
+  if (sink_value == 1234567.0f) {
+    std::fprintf(stderr, "unexpected sink value\n");
+  }
+
+  std::printf("HBM_BANDWIDTH_GBPS=%.2f\n", bandwidth_gbps);
+  std::printf("buffer_bytes=%llu\n",
+              static_cast<unsigned long long>(kBufferBytes));
+
+  check(hipEventDestroy(start), "hipEventDestroy start");
+  check(hipEventDestroy(stop), "hipEventDestroy stop");
+  check(hipFree(sink), "hipFree sink");
+  check(hipFree(input), "hipFree input");
+  return 0;
+}
